INSERT INTO posts (title, slug, summary, content, thumbnail_url, is_published, created_at, updated_at) VALUES 
('Nghệ Thuật Cắm Hoa Theo Phong Cách Tối Giản (Minimalism)', 'nghe-thuat-cam-hoa-theo-phong-cach-toi-gian', 'Phong cách minimalism không chỉ ứng dụng trong thiết kế nội thất mà còn đang trở thành xu hướng mới trong nghệ thuật cắm hoa hiện đại.', '<p>Phong cách cắm hoa tối giản tập trung vào việc sử dụng ít cành hoa nhưng tạo ra được sự tinh tế, thanh lịch tối đa. Thay vì sử dụng những bó hoa rực rỡ và đồ sộ, phong cách này chú trọng vào không gian trống, đường nét của cành lá và sự cân bằng màu sắc.</p><p><img src="https://images.unsplash.com/photo-1563241527-3004b7be0ffd?w=1000&auto=format&fit=crop" style="width: 100%; border-radius: 8px; margin: 20px 0;"/></p><h3>1. Nguyên tắc cơ bản</h3><ul><li><strong>Không gian trống (Negative Space):</strong> Là linh hồn của thiết kế. Khoảng không gian này giúp mắt người xem có điểm nghỉ và tập trung vào vẻ đẹp của từng bông hoa.</li><li><strong>Bình hoa:</strong> Ưu tiên các loại bình gốm sứ trơn, thủy tinh trong suốt với hình khối đơn giản.</li><li><strong>Số lượng:</strong> Thường sử dụng quy tắc số lẻ (1, 3, 5 bông) để tạo sự tự nhiên.</li></ul><h3>2. Các loại hoa phù hợp</h3><p>Những loài hoa có hình dáng độc đáo, đường cong mềm mại như Lan Hồ Điệp, Thiên Điểu, Hồng Môn hay các loại cành khô, cành khô trụi lá là lựa chọn hoàn hảo.</p>', 'https://images.unsplash.com/photo-1563241527-3004b7be0ffd?w=800&auto=format&fit=crop', true, NOW(), NOW()),

('Bí Quyết Chăm Sóc Cây Cảnh Trong Nhà Luôn Tươi Tốt', 'bi-quyet-cham-soc-cay-canh-trong-nha', 'Bạn yêu thích cây xanh nhưng luôn gặp khó khăn trong việc giữ chúng sống sót? Dưới đây là những bí quyết cốt lõi.', '<p>Trồng cây trong nhà giúp thanh lọc không khí và mang lại sinh khí cho không gian sống. Tuy nhiên, mỗi loại cây lại có một nhu cầu riêng. Việc thấu hiểu "ngôn ngữ" của cây sẽ giúp bạn trở thành một người làm vườn điêu luyện.</p><h3>1. Ánh sáng là yếu tố quyết định</h3><p>Hầu hết các loại cây trong nhà ưa ánh sáng gián tiếp. Hãy đặt chúng gần cửa sổ nhưng tránh ánh nắng gắt trực tiếp vào buổi trưa. Nếu nhà bạn thiếu sáng, hãy ưu tiên các loại cây như Kim Tiền, Lưỡi Hổ hay Trầu Bà.</p><h3>2. Quy tắc tưới nước "Vàng"</h3><ul><li>Chỉ tưới khi mặt đất đã khô khoảng 2-3 cm. Hãy dùng ngón tay để kiểm tra độ ẩm thay vì tưới theo lịch cố định.</li><li>Luôn đảm bảo chậu cây có lỗ thoát nước để tránh tình trạng ngập úng gây thối rễ.</li></ul><h3>3. Vệ sinh lá cây</h3><p>Thường xuyên dùng khăn ẩm lau nhẹ bề mặt lá để làm sạch bụi bẩn, giúp cây quang hợp tốt hơn và luôn bóng bẩy.</p>', 'https://images.unsplash.com/photo-1466692476877-247c0b910fa9?w=800&auto=format&fit=crop', true, NOW(), NOW()),

('Ý Nghĩa Phong Thủy Của Các Loài Hoa Thường Gặp', 'y-nghia-phong-thuy-cac-loai-hoa', 'Mỗi loài hoa không chỉ mang vẻ đẹp riêng mà còn ẩn chứa những ý nghĩa phong thủy đặc biệt, mang lại tài lộc và may mắn.', '<p>Trong quan niệm của người phương Đông, việc trưng bày hoa tươi không chỉ để làm đẹp mà còn giúp thu hút năng lượng tích cực, xua tan tà khí.</p><h3>Hoa Lan Hồ Điệp</h3><p>Được mệnh danh là "nữ hoàng của các loài hoa", Lan Hồ Điệp tượng trưng cho sự sang trọng, phú quý và sự sinh sôi nảy nở. Một chậu Lan Hồ Điệp đặt ở phòng khách sẽ mang lại vượng khí cho gia chủ.</p><h3>Hoa Cát Tường</h3><p>Đúng như tên gọi, Cát Tường mang ý nghĩa "may mắn, như ý". Loài hoa này thường được tặng trong các dịp lễ tết, khai trương với mong muốn vạn sự hanh thông.</p><h3>Hoa Hướng Dương</h3><p>Với đặc tính luôn hướng về phía mặt trời, Hướng Dương tượng trưng cho ý chí vươn lên, sức sống mãnh liệt và năng lượng dương tích cực. Rất phù hợp để đặt ở bàn làm việc.</p>', 'https://images.unsplash.com/photo-1508610048659-a06b669e3321?w=800&auto=format&fit=crop', true, NOW(), NOW());
